@flint v0 hybrid
@cb[
  ψ1=audit.log;
  ψ2=PostgreSQL;
  ψ3=JSONB;
  ρ1=7y_retention;
  ρ2=monthly_partition;
  κ1=compliance_export;
  κ2=lean_ops
]

G: schema(ψ1) ∧ partition(ρ2) ∧ retain(ρ1)
C: κ1 ∧ κ2 ∧ store(ψ2)
P: table(ψ1) → cols(core+ψ3) → partition(RANGE,occurred_at,ρ2) → idx(hot) → retention(detach+archive)

SCHEMA:
  id              BIGINT       -- snowflake/bigserial, PK part
  occurred_at     TIMESTAMPTZ  -- partition key, NOT NULL
  actor_user_id   BIGINT       -- session-derived, nullable for system
  actor_type      TEXT         -- 'user'|'service'|'system'
  tenant_id       BIGINT       -- scope filter
  action          TEXT         -- 'billing.invoice.void' style
  resource_type   TEXT
  resource_id     TEXT
  request_id      UUID         -- trace correlation
  source_ip       INET
  outcome         TEXT         -- 'ok'|'deny'|'error'
  payload         ψ3           -- structured detail, schemaless
  schema_version  SMALLINT
  PK (occurred_at, id)
